#include <imgui.h>

static bool DrawToggleSwitch(const char* id, bool value) {
    ImVec2 pos = ImGui::GetCursorScreenPos();
    ImGui::InvisibleButton(id, ImVec2(58.0f, 30.0f));
    if (ImGui::IsItemClicked()) {
        value = !value;
    }

    ImDrawList* draw_list = ImGui::GetWindowDrawList();
    const ImU32 bg = value ? IM_COL32(82, 169, 255, 255) : IM_COL32(61, 72, 88, 255);
    const float knob_x = value ? pos.x + 40.0f : pos.x + 18.0f;
    draw_list->AddRectFilled(pos, ImVec2(pos.x + 58.0f, pos.y + 30.0f), bg, 15.0f);
    draw_list->AddCircleFilled(ImVec2(knob_x, pos.y + 15.0f), 11.0f, IM_COL32(245, 248, 252, 255));
    return value;
}

void DrawToggleToolsExample() {
    static bool grid_enabled = true;
