#include <imgui.h>
#include <cstring>

struct UiTreeNode {
    int id;
    int parent;
    char label[32];
};

void DrawTreeInsertExample() {
    static UiTreeNode nodes[12] = {
        {1, 0, "Scene"},
        {2, 1, "Camera"},
        {3, 1, "Lights"},
        {4, 1, "Meshes"},
        {5, 4, "Player"}
    };
    static int node_count = 5;
    static int selected_parent = 1;
    static char new_label[32] = "New Node";

    ImGui::Begin("Tree Editor");
    ImGui::Text("أضف عناصر جديدة داخل الشجرة نفسها.");
    ImGui::InputText("New Node", new_label, sizeof(new_label));
    if (ImGui::Button("Add Node") && node_count < 12 && new_label[0]) {
        nodes[node_count].id = node_count + 1;
        nodes[node_count].parent = selected_parent;
        std::strncpy(nodes[node_count].label, new_label, sizeof(nodes[node_count].label) - 1);
        nodes[node_count].label[sizeof(nodes[node_count].label) - 1] = 0;
        node_count += 1;
        new_label[0] = 0;
    }
    ImGui::Separator();

    for (int i = 0; i < node_count; ++i) {
        if (nodes[i].parent != 0 && nodes[i].parent != 1) {
            continue;
        }
        bool opened = ImGui::TreeNodeEx(nodes[i].label, ImGuiTreeNodeFlags_OpenOnArrow);
        if (ImGui::IsItemClicked()) {
            selected_parent = nodes[i].id;
        }
        for (int child = 0; child < node_count; ++child) {
            if (nodes[child].parent == nodes[i].id) {
                ImGui::BulletText("%s", nodes[child].label);
                if (ImGui::IsItemClicked()) {
                    selected_parent = nodes[child].id;
                }
            }
        }
        if (opened) {
            ImGui::TreePop();
        }
    }

    ImGui::Separator();
    ImGui::Text("Current parent id: %d", selected_parent);
    ImGui::Text("Nodes in tree: %d", node_count);
    ImGui::End();
}

