#include <imgui.h>
#include <cstring>

static void AppendVirtualKey(char* buffer, size_t size, const char* token) {
    std::strncat(buffer, token, size - std::strlen(buffer) - 1);
}

static void RemoveLastVirtualChar(char* buffer) {
    size_t len = std::strlen(buffer);
    if (len > 0) {
        buffer[len - 1] = 0;
    }
}

void DrawVirtualKeyboardExample() {
    static char buffer[128] = "HELLO";
    static const char* row1[] = {"Q","W","E","R","T","Y","U","I","O","P"};
    static const char* row2[] = {"A","S","D","F","G","H","J","K","L"};
    static const char* row3[] = {"Z","X","C","V","B","N","M"};
    const ImVec2 key_size(36.0f, 34.0f);

    ImGui::Begin("Virtual Keyboard");
    ImGui::InputText("Text", buffer, sizeof(buffer));
    ImGui::Separator();

    for (int i = 0; i < 10; ++i) {
        if (i > 0) ImGui::SameLine();
        if (ImGui::Button(row1[i], key_size)) AppendVirtualKey(buffer, sizeof(buffer), row1[i]);
    }
    for (int i = 0; i < 9; ++i) {
        if (i > 0) ImGui::SameLine();
        if (ImGui::Button(row2[i], key_size)) AppendVirtualKey(buffer, sizeof(buffer), row2[i]);
    }
    for (int i = 0; i < 7; ++i) {
        if (i > 0) ImGui::SameLine();
        if (ImGui::Button(row3[i], key_size)) AppendVirtualKey(buffer, sizeof(buffer), row3[i]);
    }

    if (ImGui::Button("Space", ImVec2(120.0f, 34.0f))) AppendVirtualKey(buffer, sizeof(buffer), " ");
    ImGui::SameLine();
    if (ImGui::Button("Backspace", ImVec2(120.0f, 34.0f))) RemoveLastVirtualChar(buffer);
    ImGui::SameLine();
    if (ImGui::Button("Enter", ImVec2(90.0f, 34.0f))) AppendVirtualKey(buffer, sizeof(buffer), "\n");

    ImGui::Text("Length: %d", (int)std::strlen(buffer));
    ImGui::End();
}
